package com.company.snackledger.server.api;import com.company.snackledger.server.api.KioskDtos.*;import com.company.snackledger.server.model.*;import com.company.snackledger.server.repo.*;import com.company.snackledger.server.service.ApiKeyService;import jakarta.servlet.http.HttpServletRequest;import org.springframework.http.*;import org.springframework.transaction.annotation.Transactional;import org.springframework.web.bind.annotation.*;import org.springframework.web.server.ResponseStatusException;import java.math.BigDecimal;import java.time.OffsetDateTime;import java.util.*;
@RestController @RequestMapping("/api/v1/kiosk") public class KioskApiController{private final AppUserRepository users;private final ItemRepository items;private final KioskDeviceRepository kiosks;private final PurchaseRepository purchases;private final LedgerTransactionRepository ledger;private final ApiKeyService keys;public KioskApiController(AppUserRepository u,ItemRepository i,KioskDeviceRepository k,PurchaseRepository p,LedgerTransactionRepository l,ApiKeyService keys){this.users=u;this.items=i;this.kiosks=k;this.purchases=p;this.ledger=l;this.keys=keys;}
@GetMapping("/health") Health health(){return new Health("UP",OffsetDateTime.now(),"v1","0.1.0");}@GetMapping("/config") KioskConfig config(){return new KioskConfig("/api/v1/kiosk",60);} 
@GetMapping("/users/badge/{badgeId}") UserDto badge(@PathVariable String badgeId,HttpServletRequest r){requireKiosk(r);var u=users.findByBadgeId(badgeId).orElseThrow(()->new ResponseStatusException(HttpStatus.NOT_FOUND,"User not found"));return new UserDto(u.id,u.displayName,u.balance,u.active);} @GetMapping("/users/search") List<UserDto> userSearch(@RequestParam String query,HttpServletRequest r){requireKiosk(r);return users.findTop10ByDisplayNameContainingIgnoreCase(query).stream().map(u->new UserDto(u.id,u.displayName,u.balance,u.active)).toList();}
@GetMapping("/items/barcode/{barcode}") ItemDto barcode(@PathVariable String barcode,HttpServletRequest r){requireKiosk(r);var i=items.findByBarcode(barcode).orElseThrow(()->new ResponseStatusException(HttpStatus.NOT_FOUND,"Item not found"));return new ItemDto(i.id,i.name,i.barcode,i.price,i.active);}@GetMapping("/items/search") List<ItemDto> itemSearch(@RequestParam String query,HttpServletRequest r){requireKiosk(r);return items.findTop10ByNameContainingIgnoreCase(query).stream().map(i->new ItemDto(i.id,i.name,i.barcode,i.price,i.active)).toList();}
@PostMapping("/purchases") @Transactional PurchaseResponse purchase(@RequestBody PurchaseRequest req,HttpServletRequest http){requireKiosk(http);return purchases.findByKioskIdAndRequestId(req.kioskId(),req.requestId()).map(this::toResponse).orElseGet(()->create(req));}
private PurchaseResponse create(PurchaseRequest req){var u=users.findById(req.userId()).orElseThrow(()->new ResponseStatusException(HttpStatus.NOT_FOUND,"User not found"));if(!u.active)throw new ResponseStatusException(HttpStatus.CONFLICT,"User inactive");BigDecimal total=BigDecimal.ZERO;for(var line:req.items()){if(line.quantity()<1)throw new ResponseStatusException(HttpStatus.BAD_REQUEST,"Invalid quantity");var item=items.findById(line.itemId()).orElseThrow(()->new ResponseStatusException(HttpStatus.NOT_FOUND,"Item not found"));if(!item.active)throw new ResponseStatusException(HttpStatus.CONFLICT,"Item inactive");total=total.add(item.price.multiply(BigDecimal.valueOf(line.quantity())));}var p=new Purchase();p.kioskId=req.kioskId();p.requestId=req.requestId();p.userId=u.id;p.previousBalance=u.balance;p.purchaseTotal=total;p.newBalance=u.balance.subtract(total);p.completedAt=OffsetDateTime.now();u.balance=p.newBalance;users.save(u);purchases.save(p);var lt=new LedgerTransaction();lt.userId=u.id;lt.type="PURCHASE";lt.amount=total.negate();lt.balanceAfter=u.balance;lt.reference="kiosk:"+req.kioskId()+":"+req.requestId();ledger.save(lt);return toResponse(p);}private PurchaseResponse toResponse(Purchase p){return new PurchaseResponse(p.id,p.requestId,p.userId,p.previousBalance,p.purchaseTotal,p.newBalance,p.completedAt);}private KioskDevice requireKiosk(HttpServletRequest r){String id=r.getHeader("X-Kiosk-Id"),key=r.getHeader("X-Kiosk-Api-Key");var k=kiosks.findByKioskIdentifier(id).orElseThrow(()->new ResponseStatusException(HttpStatus.UNAUTHORIZED,"Unknown kiosk"));if(!k.active)throw new ResponseStatusException(HttpStatus.FORBIDDEN,"Kiosk disabled");if(!keys.matches(key,k.apiKeyHash))throw new ResponseStatusException(HttpStatus.UNAUTHORIZED,"Invalid kiosk API key");k.lastConnectionAt=OffsetDateTime.now();k.lastKnownIpAddress=r.getRemoteAddr();kiosks.save(k);return k;}}
